// Route group + endpoint filter
var api = app.MapGroup("/api/v1")
    .RequireAuthorization()
    .AddEndpointFilter<ValidationFilter>()
    .WithOpenApi();

var orders = api.MapGroup("/orders").WithTags("Orders");

orders.MapGet("", async (
    [AsParameters] OrderQuery query,
    OrderService svc, CancellationToken ct) =>
    TypedResults.Ok(await svc.GetPagedAsync(query, ct)));

orders.MapPost("", async (
    CreateOrderDto dto, OrderService svc, CancellationToken ct) =>
{
    var order = await svc.CreateAsync(dto, ct);
    return TypedResults.Created($"/api/v1/orders/{order.Id}", order);
});

// IEndpointFilter — cross-cutting concern
public class ValidationFilter : IEndpointFilter
{
    public async ValueTask<object?> InvokeAsync(
        EndpointFilterInvocationContext ctx, EndpointFilterDelegate next)
    {
        // Validate args trước khi delegate
        return await next(ctx);
    }
}

// [AsParameters] binding struct (NET 7+) — zero alloc
public record struct OrderQuery(string? Status, int Page = 1, int PageSize = 20);
